mapper.select:
SELECT DEVICE_ID, USER_ID, PUBLIC_KEY_B64, STATUS, ENROLLED_AT, UPDATED_AT
FROM BIOMETRIC_DEVICE
WHERE DEVICE_ID = #{deviceId}

mapper.update:
UPDATE BIOMETRIC_DEVICE
SET STATUS = #{status},
    UPDATED_AT = #{updatedAt,
        typeHandler=com.biometric.poc.mapper.handler.InstantTypeHandler}
WHERE DEVICE_ID = #{deviceId}

UPDATE BIOMETRIC_DEVICE
SET STATUS = 'KEY_INVALIDATED',
    PUBLIC_KEY_B64 = NULL,
    UPDATED_AT = #{updatedAt,
        typeHandler=com.biometric.poc.mapper.handler.InstantTypeHandler}
WHERE DEVICE_ID = #{deviceId}

UPDATE BIOMETRIC_DEVICE
SET PUBLIC_KEY_B64 = #{publicKeyBase64},
    UPDATED_AT = #{updatedAt,
        typeHandler=com.biometric.poc.mapper.handler.InstantTypeHandler}
WHERE DEVICE_ID = #{deviceId}

UPDATE BIOMETRIC_DEVICE
SET PUBLIC_KEY_B64 = #{publicKeyBase64},
    STATUS = 'ACTIVE',
    UPDATED_AT = #{updatedAt,
        typeHandler=com.biometric.poc.mapper.handler.InstantTypeHandler}
WHERE DEVICE_ID = #{deviceId}
